// =============================================================
// Build Prompt — resolve variables in prompt template
// =============================================================

const item = $input.first().json;
const { resolvedConfig, variableContext, tenantId } = item;

const prompt = resolvedConfig.prompt || '';
const outputSchema = resolvedConfig.output_schema || [];

// Build context string from variable context
const contextEntries = Object.entries(variableContext)
  .map(([k, v]) => `${k}: ${JSON.stringify(v)}`)
  .join('\n');

return {
  json: {
    ...item,
    aiPayload: {
      prompt,
      context: contextEntries,
      output_schema: outputSchema,
      tenant_id: tenantId,
    },
  }
};

// =============================================================
// Parse AI Result — extract structured output from MiniMax Agent
// =============================================================

try {
  const aiOutput = $('Call MiniMax Agent').first().json;
  let parsedOutput = {};

  if (aiOutput && aiOutput.content && aiOutput.content[0] && aiOutput.content[0].text) {
    try {
      parsedOutput = JSON.parse(aiOutput.content[0].text);
    } catch {
      parsedOutput = { aiResponse: aiOutput.content[0].text };
    }
  } else if (aiOutput && aiOutput.text) {
    try {
      parsedOutput = JSON.parse(aiOutput.text);
    } catch {
      parsedOutput = { aiResponse: aiOutput.text || JSON.stringify(aiOutput) };
    }
  } else {
    parsedOutput = { aiResponse: JSON.stringify(aiOutput) };
  }

  return {
    json: {
      stepResult: {
        success: true,
        outputPayload: parsedOutput,
      },
    }
  };
} catch (e) {
  return {
    json: {
      stepResult: {
        success: false,
        error: `AI action failed: ${e.message}`,
      },
    }
  };
}
